import { describe, expect, it } from "vitest";
import { ACTIVE_STATUSES, CLOSED_STATUSES, STATUS_LABELS, type OrderStatus, isActiveStatus, statusGroup } from "./types";

const ALL: OrderStatus[] = ["placed", "acknowledged", "out_for_delivery", "delivered", "cancelled"];

describe("order status taxonomy", () => {
  it("every status is in exactly one of ACTIVE_STATUSES / CLOSED_STATUSES", () => {
    for (const s of ALL) {
      const inActive = ACTIVE_STATUSES.has(s);
      const inClosed = CLOSED_STATUSES.has(s);
      expect(inActive !== inClosed).toBe(true);
    }
  });

  it("every status has a STATUS_LABELS entry", () => {
    for (const s of ALL) expect(STATUS_LABELS[s]).toBeTruthy();
  });

  it("isActiveStatus + statusGroup agree with ACTIVE_STATUSES", () => {
    for (const s of ALL) {
      expect(isActiveStatus(s)).toBe(ACTIVE_STATUSES.has(s));
      expect(statusGroup(s)).toBe(ACTIVE_STATUSES.has(s) ? "active" : "closed");
    }
  });
});

import { describe, expect, it } from "vitest";
import { paiseToRupees } from "./types";

describe("paiseToRupees", () => {
  it("renders zero as Rs.0.00", () => {
    expect(paiseToRupees(0)).toBe("\u20B90.00");
  });
  it("renders 1234567 paise as Rs.12,345.67 (Indian grouping)", () => {
    expect(paiseToRupees(1234567)).toBe("\u20B912,345.67");
  });
  it("renders 100000000 paise as Rs.10,00,000.00", () => {
    expect(paiseToRupees(100_000_000)).toBe("\u20B910,00,000.00");
  });
  it("prefixes negatives with -", () => {
    expect(paiseToRupees(-150)).toBe("-\u20B91.50");
  });
});

import { describe, expect, it } from "vitest";
import { findRetailerByLicense, listDistributors, listOffers, searchMedicines, listOrders, getOutstandingForRetailer } from "./store";

describe("in-memory store seed", () => {
  const PILOT = "r-pilot-1";

  it("finds the pilot retailer by license number (case-insensitive)", () => {
    expect(findRetailerByLicense("MH-RP-2024-7821")?.id).toBe(PILOT);
    expect(findRetailerByLicense("mh-rp-2024-7821")?.id).toBe(PILOT);
  });

  it("lists all 4 distributors sorted by name", () => {
    const d = listDistributors();
    expect(d).toHaveLength(4);
    const names = d.map((x) => x.name);
    expect(names).toEqual([...names].sort());
  });

  it("lists 3 active offers in sortOrder", () => {
    const o = listOffers();
    expect(o).toHaveLength(3);
    expect(o.map((x) => x.sortOrder)).toEqual([1, 2, 3]);
  });

  it("empty search returns the full catalogue (20 medicines)", () => {
    expect(searchMedicines("")).toHaveLength(20);
  });

  it("search 'paracet' is case-insensitive over name/brand/generic", () => {
    const r = searchMedicines("paracet");
    expect(r.length).toBeGreaterThanOrEqual(1);
    expect(r.some((m) => m.id === "m-paracetamol-500")).toBe(true);
  });

  it("seeded orders split between active and closed groups", () => {
    const active = listOrders(PILOT, "active");
    const closed = listOrders(PILOT, "closed");
    expect(active.length).toBeGreaterThanOrEqual(1);
    expect(closed.length).toBeGreaterThanOrEqual(1);
    expect(active.every((o) => o.status === "placed" || o.status === "acknowledged" || o.status === "out_for_delivery")).toBe(true);
    expect(closed.every((o) => o.status === "delivered" || o.status === "cancelled")).toBe(true);
  });

  it("outstanding payments are seeded for the pilot retailer", () => {
    const op = getOutstandingForRetailer(PILOT);
    expect(op.length).toBe(2);
    expect(op.reduce((acc, x) => acc + x.amountDuePaise, 0)).toBe(2_300_000);
  });
});

import { describe, expect, it, beforeEach } from "vitest";
import { addCartItem, clearCart, listCartItems, createOrdersFromCart, getOrder, listOrderItems, removeCartItem } from "./store";

const PILOT = "r-pilot-1";

describe("cart and order fan-out", () => {
  beforeEach(() => clearCart(PILOT));

  it("addCartItem is idempotent on (retailerId, medicineId): adds qty", () => {
    addCartItem(PILOT, "m-paracetamol-500", 1);
    addCartItem(PILOT, "m-paracetamol-500", 2);
    const items = listCartItems(PILOT);
    expect(items).toHaveLength(1);
    expect(items[0].qty).toBe(3);
  });

  it("removeCartItem removes the line, returns true on hit", () => {
    addCartItem(PILOT, "m-paracetamol-500", 1);
    expect(removeCartItem(PILOT, "m-paracetamol-500")).toBe(true);
    expect(listCartItems(PILOT)).toEqual([]);
  });

  it("createOrdersFromCart fans out one Order per distinct distributorId", () => {
    addCartItem(PILOT, "m-paracetamol-500", 2); // d-mediplus
    addCartItem(PILOT, "m-vitd3-60k", 1); // d-omsai
    addCartItem(PILOT, "m-amoxicillin-500", 1); // d-mediplus again
    const created = createOrdersFromCart(PILOT);
    expect(created.length).toBe(2);
    const distributorIds = new Set(created.map((c) => c.distributorId));
    expect(distributorIds).toEqual(new Set(["d-mediplus", "d-omsai"]));
    for (const c of created) {
      const order = getOrder(c.id);
      expect(order?.status).toBe("placed");
      const items = listOrderItems(c.id);
      expect(items.length).toBeGreaterThan(0);
      const sum = items.reduce((acc, x) => acc + x.lineTotalPaise, 0);
      expect(sum).toBe(order?.totalPaise);
    }
    expect(listCartItems(PILOT)).toEqual([]);
  });

  it("createOrdersFromCart returns [] when the cart is empty", () => {
    expect(createOrdersFromCart(PILOT)).toEqual([]);
  });
});
